create table if not exists profiles (user_id uuid primary key references auth.users(id) on delete cascade, display_name text, created_at timestamptz default now());
create table if not exists user_preferences (user_id uuid primary key references auth.users(id) on delete cascade, ai_workouts boolean default true, ai_nutrition boolean default true, ai_body boolean default true, ai_health boolean default false);
create table if not exists exercises (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null);
create table if not exists workout_plans (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null, active boolean default false);
create table if not exists workout_plan_days (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, plan_id uuid references workout_plans(id) on delete cascade, name text not null);
create table if not exists workout_plan_exercises (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, day_id uuid references workout_plan_days(id) on delete cascade, exercise_name text not null, target_sets int, target_reps text, target_rpe numeric, rest_seconds int, position int default 0);
create table if not exists workout_sessions (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, started_at timestamptz default now(), finished_at timestamptz, notes text);
create table if not exists workout_session_exercises (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, session_id uuid references workout_sessions(id) on delete cascade, name text not null, position int default 0);
create table if not exists workout_sets (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, session_exercise_id uuid references workout_session_exercises(id) on delete cascade, weight numeric, reps int, rpe numeric, set_type text);
create table if not exists foods (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null, calories numeric, protein numeric, carbohydrates numeric, fat numeric, fiber numeric);
create table if not exists meals (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null);
create table if not exists meal_items (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, meal_id uuid references meals(id) on delete cascade, food_id uuid references foods(id), amount numeric);
create table if not exists food_logs (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, logged_at timestamptz default now(), meal text, name text, calories numeric, protein numeric, carbohydrates numeric, fat numeric, fiber numeric);
create table if not exists nutrition_targets (user_id uuid primary key references auth.users(id) on delete cascade, calories numeric, protein numeric, carbohydrates numeric, fat numeric);
create table if not exists water_logs (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, logged_at timestamptz default now(), milliliters int not null);
create table if not exists body_measurements (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, measured_at timestamptz default now(), weight_kg numeric, body_fat_percent numeric, waist_cm numeric, chest_cm numeric, shoulders_cm numeric, neck_cm numeric, left_arm_cm numeric, right_arm_cm numeric, hips_cm numeric, left_thigh_cm numeric, right_thigh_cm numeric, notes text);
create table if not exists recovery_checkins (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, checked_at date default current_date, sleep_hours numeric, sleep_quality int, energy int, stress int, motivation int, soreness int, pain boolean, pain_area text, notes text);
create table if not exists readiness_scores (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, created_at timestamptz default now(), score int, confidence text, explanation text);
create table if not exists habits (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null);
create table if not exists habit_logs (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, habit_id uuid references habits(id) on delete cascade, completed_at date default current_date);
create table if not exists ai_conversations (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, created_at timestamptz default now());
create table if not exists ai_messages (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, conversation_id uuid references ai_conversations(id) on delete cascade, role text, content text, created_at timestamptz default now());
create table if not exists ai_actions (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, action_type text, payload jsonb, status text default 'pending');
create table if not exists daily_insights (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, insight_date date default current_date, summary text, signals jsonb);
create table if not exists generated_reports (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, report_type text, metrics jsonb, summary text, created_at timestamptz default now());
alter table profiles enable row level security;alter table user_preferences enable row level security;alter table exercises enable row level security;alter table workout_plans enable row level security;alter table workout_plan_days enable row level security;alter table workout_plan_exercises enable row level security;alter table workout_sessions enable row level security;alter table workout_session_exercises enable row level security;alter table workout_sets enable row level security;alter table foods enable row level security;alter table meals enable row level security;alter table meal_items enable row level security;alter table food_logs enable row level security;alter table nutrition_targets enable row level security;alter table water_logs enable row level security;alter table body_measurements enable row level security;alter table recovery_checkins enable row level security;alter table readiness_scores enable row level security;alter table habits enable row level security;alter table habit_logs enable row level security;alter table ai_conversations enable row level security;alter table ai_messages enable row level security;alter table ai_actions enable row level security;alter table daily_insights enable row level security;alter table generated_reports enable row level security;
